// ============================================
// CODE AGENT 1: VALIDAR AFECTADO
// ============================================
// Busca afectado en Sheets y mapea documentos base

const input = $input.all();
const requestData = input[0].json;
const afectadosRows = input[1].json;

// Buscar afectado por nombre o email
let afectado = afectadosRows.find(row => 
  row.Afectado?.toLowerCase() === requestData.nombre?.toLowerCase() || 
  row.Email?.toLowerCase() === requestData.email?.toLowerCase()
);

if (!afectado) {
  throw new Error(`❌ Afectado no encontrado: ${requestData.nombre || requestData.email}`);
}

// Validar que tenga póliza activa
if (!afectado.Poliza || afectado.Status !== 'ACTIVO') {
  throw new Error(`❌ Afectado sin póliza activa: ${afectado.Afectado}`);
}

// Mapear documentos base requeridos
const baseDocs = {
  ine: afectado.INE_URL || null,
  bbva: afectado.BBVA_URL || null,
  domicilio: afectado.DOMICILIO_URL || null,
  poliza: afectado.Poliza,
  numeroAsegurado: afectado.NumeroAsegurado,
  telefono: afectado.Telefono,
  direccion: afectado.Direccion
};

// Validar que existan los 3 docs obligatorios
const missingDocs = [];
if (!baseDocs.ine) missingDocs.push('INE');
if (!baseDocs.bbva) missingDocs.push('Estado de Cuenta BBVA');
if (!baseDocs.domicilio) missingDocs.push('Comprobante Domicilio');

if (missingDocs.length > 0) {
  throw new Error(`❌ Documentos faltantes para ${afectado.Afectado}: ${missingDocs.join(', ')}`);
}

// Retornar datos consolidados
return [{
  json: {
    ...requestData,
    afectado: {
      nombre: afectado.Afectado,
      email: afectado.Email,
      telefono: afectado.Telefono,
      poliza: afectado.Poliza,
      numeroAsegurado: afectado.NumeroAsegurado
    },
    baseDocs,
    status: 'AFECTADO_VALIDADO',
    timestamp: new Date().toISOString()
  }
}];

// ============================================
// CODE AGENT 2: VALIDACIÓN OCR + EXTRACCIÓN DATOS MX
// ============================================

const input = $input.first().json;
const ocrText = input.text || '';
const requestData = input;

// Regex patterns para facturas médicas mexicanas
const patterns = {
  // Monto: busca "Total", "$", números con comas
  monto: /(?:total|importe|monto)[:\s]*\$?\s*([0-9,]+\.?[0-9]{0,2})/gi,

  // RFC (México): AAAA######XXX
  rfc: /[A-ZÑ&]{3,4}\d{6}[A-Z0-9]{3}/g,

  // Proveedor médico
  proveedor: /(?:hospital|clínica|clinic|centro médico|doctor|dr\.|dra\.|consultorio|laboratorio)[\s\w]+/gi,

  // Fecha en formatos MX: DD/MM/YYYY, DD-MM-YYYY
  fecha: /\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4}/g,

  // Concepto médico
  concepto: /(?:consulta|estudio|análisis|cirugía|operación|medicamento|tratamiento|terapia|radiografía|ultrasonido|tomografía)/gi,

  // Folio/Factura
  folio: /(?:folio|factura|recibo)[:\s#]*([A-Z0-9\-]+)/gi
};

// Extraer información
const montoMatches = [...ocrText.matchAll(patterns.monto)];
const extractions = {
  monto: montoMatches.length > 0 
    ? montoMatches[montoMatches.length - 1][1].replace(/,/g, '') 
    : null,

  rfc: ocrText.match(patterns.rfc)?.[0] || null,

  proveedor: ocrText.match(patterns.proveedor)?.[0]?.trim() || 'Proveedor No Identificado',

  fecha: ocrText.match(patterns.fecha)?.[0] || new Date().toISOString().split('T')[0],

  concepto: ocrText.match(patterns.concepto)?.[0]?.toLowerCase() || 'servicio médico',

  folio: ocrText.match(patterns.folio)?.[1] || `AUTO-${Date.now()}`
};

// ============================================
// VALIDACIONES CRÍTICAS
// ============================================

const errors = [];
const warnings = [];

// 1. Validar monto
if (!extractions.monto) {
  errors.push('No se detectó monto en la factura');
} else {
  const montoNumerico = parseFloat(extractions.monto);
  if (isNaN(montoNumerico) || montoNumerico <= 0) {
    errors.push(`Monto inválido: ${extractions.monto}`);
  } else if (montoNumerico > 500000) {
    warnings.push(`Monto alto detectado: $${montoNumerico.toLocaleString('es-MX')} MXN`);
  }
  extractions.montoNumerico = montoNumerico;
}

// 2. Validar RFC (opcional pero recomendado)
if (!extractions.rfc) {
  warnings.push('RFC no detectado en factura');
}

// 3. Validar fecha
if (!extractions.fecha) {
  warnings.push('Fecha no detectada, usando fecha actual');
}

// 4. Validar que el texto OCR no esté vacío
if (ocrText.length < 50) {
  errors.push('Texto OCR muy corto, posible error en lectura');
}

// ============================================
// RESULTADO
// ============================================

if (errors.length > 0) {
  throw new Error(`❌ OCR Validation Failed:\n${errors.join('\n')}`);
}

return [{
  json: {
    ...requestData,
    ocr_raw: ocrText,
    ocr_data: extractions,
    validaciones: {
      errors: errors,
      warnings: warnings,
      confidence: ocrText.length > 200 ? 'ALTA' : 'MEDIA'
    },
    status: 'OCR_VALIDADO',
    timestamp: new Date().toISOString()
  }
}];

