// ============================================
// PDF FORMS FILLER
// ============================================
// Genera los PDFs con datos del afectado y OCR

const data = $input.first().json;

// Mapeo de campos según tipo de evento
const formsData = {
  // Campos comunes a todos los eventos
  common: {
    txtNombre: data.afectado.nombre,
    txtPoliza: data.afectado.poliza,
    txtNumeroAsegurado: data.afectado.numeroAsegurado,
    txtTelefono: data.afectado.telefono,
    txtEmail: data.afectado.email,
    txtFecha: new Date().toLocaleDateString('es-MX')
  },

  // Campos específicos por evento
  reembolso: {
    txtMontoTotalFacturas: data.ocr_data.montoNumerico?.toFixed(2) || '0.00',
    txtProveedorMedico: data.ocr_data.proveedor,
    txtFechaServicio: data.ocr_data.fecha,
    txtConcepto: data.ocr_data.concepto,
    txtFolioFactura: data.ocr_data.folio,
    txtRFC: data.ocr_data.rfc || 'N/A',
    txtNoFacturasReclamar: '1'
  },

  medicamentos: {
    chkMedicamentos: true,
    txtMontoMedicamentos: data.ocr_data.montoNumerico?.toFixed(2) || '0.00',
    txtFarmacia: data.ocr_data.proveedor
  },

  nuevo: {
    txtNumeroSiniestro: `SGMM-${Date.now()}`,
    txtFechaOcurrencia: data.ocr_data.fecha,
    txtDiagnostico: data.ocr_data.concepto
  }
};

// Combinar campos según el tipo de evento
const evento = data.evento || 'reembolso';
const pdfFields = {
  ...formsData.common,
  ...formsData[evento]
};

return [{
  json: {
    ...data,
    pdfFields,
    pdfTemplate: `marsh-sgmm-${evento}`,
    status: 'PDF_PREPARADO'
  }
}];

// ============================================
// CODE AGENT 3: FINAL CHECKLIST
// ============================================
// Verifica que todos los documentos y campos estén completos

const data = $input.first().json;

// Definir campos requeridos por tipo de evento
const requiredFieldsByEvent = {
  nuevo: ['txtNombre', 'txtPoliza', 'txtNumeroSiniestro', 'txtNumeroAsegurado'],
  reembolso: ['txtNombre', 'txtPoliza', 'txtMontoTotalFacturas', 'txtProveedorMedico', 'txtNoFacturasReclamar'],
  medicamentos: ['txtNombre', 'txtPoliza', 'chkMedicamentos', 'txtMontoMedicamentos']
};

const evento = data.evento || 'reembolso';
const requiredFields = requiredFieldsByEvent[evento] || [];
const pdfFields = data.pdfFields || {};

// ============================================
// CHECKLIST 1: CAMPOS PDF
// ============================================
const missingFields = requiredFields.filter(field => {
  const value = pdfFields[field];
  return !value || value === '' || value === null || value === undefined;
});

if (missingFields.length > 0) {
  throw new Error(`❌ Campos PDF faltantes (${evento}): ${missingFields.join(', ')}`);
}

// ============================================
// CHECKLIST 2: DOCUMENTOS BASE
// ============================================
const baseDocs = data.baseDocs || {};
const requiredDocs = ['ine', 'bbva', 'domicilio'];
const missingDocs = requiredDocs.filter(doc => !baseDocs[doc]);

if (missingDocs.length > 0) {
  throw new Error(`❌ Documentos base faltantes: ${missingDocs.join(', ')}`);
}

// ============================================
// CHECKLIST 3: VALIDACIÓN OCR
// ============================================
if (!data.ocr_data || !data.ocr_data.montoNumerico) {
  throw new Error('❌ Datos OCR incompletos');
}

if (data.ocr_data.montoNumerico <= 0) {
  throw new Error('❌ Monto OCR inválido o cero');
}

// ============================================
// CHECKLIST 4: INFORMACIÓN AFECTADO
// ============================================
if (!data.afectado || !data.afectado.email) {
  throw new Error('❌ Email del afectado no encontrado');
}

// ============================================
// GENERAR REPORTE DE CHECKLIST
// ============================================
const checklistReport = {
  evento: evento,
  afectado: data.afectado.nombre,
  camposPDF: {
    requeridos: requiredFields.length,
    completos: requiredFields.length - missingFields.length,
    status: '✅ COMPLETO'
  },
  documentosBase: {
    requeridos: requiredDocs.length,
    completos: requiredDocs.length - missingDocs.length,
    status: '✅ COMPLETO'
  },
  datosOCR: {
    monto: data.ocr_data.montoNumerico,
    proveedor: data.ocr_data.proveedor,
    confidence: data.validaciones?.confidence || 'MEDIA',
    status: '✅ VALIDADO'
  },
  timestamp: new Date().toISOString()
};

// Calcular nombre del ZIP
const zipName = `${data.afectado.nombre.replace(/\s+/g, '_')}_${evento}_${Date.now()}`;

return [{
  json: {
    ...data,
    checklistReport,
    zipName,
    status: 'CHECKLIST_COMPLETO',
    readyForZip: true
  }
}];

// ============================================
// CODE AGENT 3.5: VALIDAR DRIVE UPLOAD
// ============================================
// Verifica que el archivo se subió correctamente a Drive

const driveData = $input.first().json;
const previousData = $input.first().json;

// Validar que existe webViewLink (indicador de subida exitosa)
if (!driveData.webViewLink) {
  throw new Error('❌ Drive upload falló: No se generó link de visualización');
}

// Validar que existe el ID del archivo
if (!driveData.id) {
  throw new Error('❌ Drive upload falló: No se generó ID de archivo');
}

// Crear link compartible (cambiar permisos de view a sharing)
const shareableLink = driveData.webViewLink
  .replace('/view?usp=drivesdk', '/view?usp=sharing');

// Crear link directo de descarga
const downloadLink = `https://drive.google.com/uc?export=download&id=${driveData.id}`;

return [{
  json: {
    ...previousData,
    drive: {
      fileId: driveData.id,
      fileName: driveData.name,
      webViewLink: shareableLink,
      downloadLink: downloadLink,
      size: driveData.size,
      mimeType: driveData.mimeType,
      createdTime: driveData.createdTime
    },
    status: 'DRIVE_UPLOAD_OK',
    emailReady: true
  }
}];

